mapper.select:
SELECT
    category_id,
    email,
    owner_type,
    category_name,
    color
FROM category
WHERE category_id = #{categoryId}
  AND email = #{email}
  AND owner_type = #{ownerType}

mapper.update:
UPDATE category
SET
    category_name = #{categoryName},
    color = #{color}
WHERE category_id = #{categoryId}
  AND email = #{email}
  AND owner_type = #{ownerType}

mapper.delete:
DELETE FROM category
WHERE category_id = #{categoryId}
  AND email = #{email}
  AND owner_type = #{ownerType}

mapper.select:
SELECT COUNT(*)
FROM task t
INNER JOIN category c
    ON c.category_id = t.category_id
WHERE t.category_id = #{categoryId}
  AND t.email = #{email}
  AND t.owner_type = #{ownerType}
  AND c.email = #{email}
  AND c.owner_type = #{ownerType}

